import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

// Tests for the behavior documented in src/merge.js:
//   - overlapping intervals are merged      ([1,4],[3,6] -> [1,6])
//   - touching intervals are merged         ([1,2],[2,3] -> [1,3])
//   - disjoint intervals stay separate
//   - [] -> []
//   - result is a new array, sorted by start ascending
//   - the input array and its pairs are never mutated
//   - throws RangeError if any pair has start > end

describe("mergeIntervals", () => {
  describe("empty and singleton inputs", () => {
    it("returns [] for []", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    it("returns a single interval unchanged in value", () => {
      expect(mergeIntervals([[1, 5]])).toEqual([[1, 5]]);
    });

    it("preserves a zero-width (point) interval", () => {
      expect(mergeIntervals([[3, 3]])).toEqual([[3, 3]]);
    });
  });

  describe("overlapping intervals are merged", () => {
    it("merges the documented example [1,4],[3,6] -> [1,6]", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("merges when one interval is fully contained in another", () => {
      expect(mergeIntervals([[1, 10], [3, 6]])).toEqual([[1, 10]]);
    });

    it("keeps the larger end when the contained interval comes first", () => {
      expect(mergeIntervals([[3, 6], [1, 10]])).toEqual([[1, 10]]);
    });

    it("merges a chain of successively overlapping intervals into one", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [4, 8], [7, 10]])).toEqual([
        [1, 10],
      ]);
    });

    it("merges duplicate intervals into a single interval", () => {
      expect(mergeIntervals([[2, 5], [2, 5], [2, 5]])).toEqual([[2, 5]]);
    });

    it("does not extend the end when a later interval is shorter", () => {
      // [1,8] overlaps [2,4]; the merged end must stay 8, not shrink to 4.
      expect(mergeIntervals([[1, 8], [2, 4]])).toEqual([[1, 8]]);
    });
  });

  describe("touching intervals are merged", () => {
    it("merges the documented example [1,2],[2,3] -> [1,3]", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges a run of end-to-end touching intervals", () => {
      expect(mergeIntervals([[0, 1], [1, 2], [2, 3], [3, 4]])).toEqual([
        [0, 4],
      ]);
    });

    it("merges a point interval that touches the start of another", () => {
      expect(mergeIntervals([[5, 5], [5, 9]])).toEqual([[5, 9]]);
    });

    it("merges a point interval that touches the end of another", () => {
      expect(mergeIntervals([[1, 5], [5, 5]])).toEqual([[1, 5]]);
    });
  });

  describe("disjoint intervals stay separate", () => {
    it("keeps two clearly separated intervals apart", () => {
      expect(mergeIntervals([[1, 2], [4, 5]])).toEqual([[1, 2], [4, 5]]);
    });

    it("keeps intervals separated by the smallest gap apart", () => {
      // end=2 and start=3 do not touch (2 < 3), so they must not merge.
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("keeps many disjoint intervals separate and ordered", () => {
      expect(mergeIntervals([[1, 2], [4, 5], [7, 8]])).toEqual([
        [1, 2],
        [4, 5],
        [7, 8],
      ]);
    });
  });

  describe("sorting by start ascending", () => {
    it("sorts disjoint intervals given out of order", () => {
      expect(mergeIntervals([[7, 8], [1, 2], [4, 5]])).toEqual([
        [1, 2],
        [4, 5],
        [7, 8],
      ]);
    });

    it("merges overlapping intervals given out of order", () => {
      expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
    });

    it("produces a strictly increasing sequence of starts", () => {
      const result = mergeIntervals([[10, 12], [1, 3], [5, 6], [2, 4]]);
      const starts = result.map(([s]) => s);
      const ascending = [...starts].sort((a, b) => a - b);
      expect(starts).toEqual(ascending);
    });
  });

  describe("negative and mixed-sign coordinates", () => {
    it("merges overlapping intervals spanning zero", () => {
      expect(mergeIntervals([[-5, 0], [-2, 3]])).toEqual([[-5, 3]]);
    });

    it("keeps disjoint negative intervals separate and ordered", () => {
      expect(mergeIntervals([[-1, 0], [-5, -4]])).toEqual([
        [-5, -4],
        [-1, 0],
      ]);
    });

    it("merges intervals touching at a negative coordinate", () => {
      expect(mergeIntervals([[-8, -4], [-4, -1]])).toEqual([[-8, -1]]);
    });
  });

  describe("non-integer coordinates", () => {
    it("merges overlapping fractional intervals", () => {
      expect(mergeIntervals([[1.5, 2.5], [2.0, 3.0]])).toEqual([[1.5, 3.0]]);
    });

    it("keeps fractional intervals with a tiny gap separate", () => {
      expect(mergeIntervals([[0, 0.1], [0.2, 0.3]])).toEqual([
        [0, 0.1],
        [0.2, 0.3],
      ]);
    });
  });

  describe("throws RangeError on invalid intervals", () => {
    it("throws when a single pair has start > end", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    it("throws when any pair among valid ones is inverted", () => {
      expect(() => mergeIntervals([[1, 2], [9, 4], [10, 11]])).toThrow(
        RangeError,
      );
    });

    it("does not throw for a valid zero-width interval (start == end)", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });

    it("reports the offending interval in the error message", () => {
      expect(() => mergeIntervals([[7, 2]])).toThrow("[7, 2]");
    });

    it("validates before producing output (throws even with valid neighbors)", () => {
      expect(() => mergeIntervals([[0, 10], [3, 1]])).toThrow(RangeError);
    });
  });

  describe("does not mutate the input", () => {
    it("leaves the outer array's length and element order unchanged", () => {
      const input = [[7, 8], [1, 2], [4, 5]];
      mergeIntervals(input);
      expect(input).toEqual([[7, 8], [1, 2], [4, 5]]);
    });

    it("leaves the inner pairs unchanged when intervals are merged", () => {
      const a = [1, 4];
      const b = [3, 6];
      const input = [a, b];
      mergeIntervals(input);
      expect(a).toEqual([1, 4]);
      expect(b).toEqual([3, 6]);
    });

    it("returns a new array, not the input reference", () => {
      const input = [[1, 2]];
      expect(mergeIntervals(input)).not.toBe(input);
    });

    it("returns pairs that are new arrays, not the original pair references", () => {
      const pair = [1, 2];
      const result = mergeIntervals([pair]);
      expect(result[0]).not.toBe(pair);
    });

    it("keeps the returned intervals independent of the input after mutation", () => {
      const input = [[1, 4], [3, 6]];
      const result = mergeIntervals(input);
      // Mutating the input afterward must not affect the returned result.
      input[0][0] = 999;
      expect(result).toEqual([[1, 6]]);
    });
  });

  describe("larger integrated scenario", () => {
    it("handles a mix of overlapping, touching, and disjoint intervals out of order", () => {
      const input = [
        [15, 18],
        [1, 3],
        [8, 10],
        [2, 6],
        [10, 12],
        [20, 20],
      ];
      expect(mergeIntervals(input)).toEqual([
        [1, 6],
        [8, 12],
        [15, 18],
        [20, 20],
      ]);
      // Input untouched.
      expect(input).toEqual([
        [15, 18],
        [1, 3],
        [8, 10],
        [2, 6],
        [10, 12],
        [20, 20],
      ]);
    });
  });
});

